\t\t\t</view>\n\t\t\t\t<view v-else class=\"picker-input\" @click=\"openAddressPopup\">\n\t\t\t\t\t<text :class=\"selectedAddress ? 'value-text' : 'placeholder-text'\">\n\t\t\t\t\t\t{{ selectedAddress ? selectedAddressText : '请选择服务地址' }}\n\t\t\t\t\t</text>\n\t\t\t\t</view>\n\t\t\t</view>\n\t\t\t<view class=\"row\">\n\t\t\t\t<text class=\"label\">服务项目</text>\n\t\t\t\t<text class=\"value\">{{ serviceName || '上门服务' }}</text>\n\t\t\t</view>\n\t\t\t<view class=\"row\">\n\t\t\t\t<text class=\"label\">上门时间</text>\n\t\t\t\t<view class=\"picker-input\" @click=\"openDateTimePopup\">\n\t\t\t\t\t<text :class=\"timeText ? 'value-text' : 'placeholder-text'\">\n\t\t\t\t\t\t{{ timeText || '请选择预约日期和时间' }}\n\t\t\t\t\t</text>\n\t\t\t\t</view>\n\t\t\t</view>\n\t\t\t<view class=\"row\">\n\t\t\t\t<text class=\"label\">备注</text>\n\t\t\t\t<textarea class=\"remark-input\" v-model=\"remark\" placeholder=\"可填写注意事项（选填）\" maxlength=\"200\" />\n\t\t\t</view>\n\t\t\t<button class=\"submit\" @click=\"submitReserve\">提交预约</button>\n\t\t</view>\n\n\t\t<u-popup v-model=\"showDateTimePopup\" mode=\"bottom\" border-radius=\"18\" :closeable=\"true\">\n\t\t\t<view class=\"datetime-popup\">\n\t\t\t\t<view class=\"popup-title\">选择预约时间</view>\n\t\t\t\t<view class=\"popup-row\">\n\t\t\t\t\t<text class=\"popup-label\">日期</text>\n\t\t\t\t\t<picker mode=\"date\" :value=\"dateValue\" @change=\"onDateChange\">\n\t\t\t\t\t\t<view class=\"picker-btn\">{{ dateValue }}</view>\n\t\t\t\t\t</picker>\n\t\t\t\t</view>\n\t\t\t\t<view class=\"popup-row\">\n\t\t\t\t\t<text class=\"popup-label\">时间</text>\n\t\t\t\t\t<picker mode=\"time\" :value=\"timeValue\" @change=\"onTimeChange\">\n\t\t\t\t\t\t<view class=\"picker-btn\">{{ timeValue }}</view>\n\t\t\t\t\t</picker>\n\t\t\t\t</view>\n\t\t\t\t<button class=\"confirm-btn\" @click=\"confirmDateTime\">确定</button>\n\t\t\t</view>\n\t\t</u-popup>\n\n\t\t<u-popup v-model=\"showAddressPopup\" mode=\"bottom\" border-radius=\"18\" :closeable=\"true\">\n\t\t\t<view class=\"address-popup\">\n\t\t\t\t<view class=\"popup-title\">选择服务地址</view>\n\t\t\t\t<view class=\"address-list\" v-if=\"addressList.length\">\n\t\t\t\t\t<view\n\t\t\t\t\t\tclass=\"address-item\"\n\t\t\t\t\t\tv-for=\"item in addressList\"\n\t\t\t\t\t\t:key=\"item.id\"\n\t\t\t\t\t\t@click=\"chooseAddress(item)\"\n\t\t\t\t\t>\n\t\t\t\t\t\t<view class=\"address-item-main\">\n\t\t\t\t\t\t\t<view class=\"address-item-top\">\n\t\t\t\t\t\t\t\t<text class=\"address-name\">{{ item.consignee }}</text>\n\t\t\t\t\t\t\t\t<text class=\"address-phone\">{{ item.phone }}</text>\n\t\t\t\t\t\t\t</view>\n\t\t\t\t\t\t\t<view class=\"address-detail\">{{ formatAddress(item) }}</view>\n\t\t\t\t\t\t</view>\n\t\t\t\t\t\t<text class=\"address-check\" v-if=\"selectedAddress && selectedAddress.id === item.id\">已选</text>\n\t\t\t\t\t</view>\n\t\t\t\t</view>\n\t\t\t\t<view class=\"empty-tip\" v-else>\n\t\t\t\t\t<text>暂无可用地址</text>\n\t\t\t\t\t<button class=\"go-add-btn\" @click=\"goAddAddress\">去添加地址</button>\n\t\t\t\t</view>\n\t\t\t</view>\n\t\t</u-popup>\n\t</view>\n</template>\n\n<script>\nimport api from '../utils/http.js'\n\nexport default {\n\tdata() {\n\t\tconst now = new Date()\n\t\tconst pad = n => String(n).padStart(2, '0')\n\t\tconst dateValue = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`\n\t\tconst timeValue = `${pad(now.getHours())}:${pad(now.getMinutes())}`\n\t\treturn {\n\t\t\tserviceName: '',\n\t\t\tworkerId: 0,\n\t\t\tcategoryId: 1,\n\t\t\taddressList: [],\n\t\t\tselectedAddress: null,\n\t\t\tshowAddressPopup: false,\n\t\t\tremark: '',\n\t\t\ttimeText: '',\n\t\t\tshowDateTimePopup: false,\n\t\t\tdateValue,\n\t\t\ttimeValue\n\t\t}\n\t},\n\tcomputed: {\n\t\tselectedAddressText() {\n\t\t\tif (!this.selectedAddress) return ''\n\t\t\treturn `${this.selectedAddress.consignee} ${this.selectedAddress.phone} ${this.formatAddress(this.selectedAddress)}`\n\t\t}\n\t},\n\tonLoad(options) {\n\t\tthis.serviceName = decodeURIComponent(options.name || '')\n\t\tthis.workerId = Number(options.workerId || 0)\n\t\tthis.categoryId = Number(options.categoryId || 1)\n\t\tthis.fetchAddressList()\n\t},\n\tmethods: {\n\t\tasync fetchAddressList() {\n\t\t\tconst token = uni.getStorageSync('Token') || ''\n\t\t\tif (!token) return\n\n\t\t\ttry {\n\t\t\t\tconst res = await api.createRequest({\n\t\t\t\t\turl: '/house/address/my',\n\t\t\t\t\tmethod: 'get',\n\t\t\t\t\ttoken\n\t\t\t\t}, {})\n\t\t\t\tconst list = Array.isArray(res?.data) ? res.data : []\n\t\t\t\tthis.addressList = list\n\n\t\t\t\tif (list.length === 0) {\n\t\t\t\t\tthis.selectedAddress = null\n\t\t\t\t\treturn\n\t\t\t\t}\n\n\t\t\t\t// 优先选 isDefault === 1 的地址\n\t\t\t\tconst defaultItem = list.find(item => Number(item.isDefault) === 1)\n\t\t\t\tif (defaultItem) {\n\t\t\t\t\tthis.selectedAddress = defaultItem\n\t\t\t\t} else {\n\t\t\t\t\t// 无默认地址，自动将第一条设为默认\n\t\t\t\t\tthis.selectedAddress = list[0]\n\t\t\t\t\ttry {\n\t\t\t\t\t\tawait api.createRequest({\n\t\t\t\t\t\t\turl: '/house/address/update',\n\t\t\t\t\t\t\tmethod: 'put',\n\t\t\t\t\t\t\ttoken\n\t\t\t\t\t\t}, { \t\t\t\tid: list[0].id,\n\t\t\t\t\t\tisDefault: 1,\n\t\t\t\t\t\tconsignee: list[0].consignee,\n\t\t\t\t\t\tphone: list[0].phone,\n\t\t\t\t\t\tprovince: '四川省',\n\t\t\t\t\t\tcity: '南充市',\n\t\t\t\t\t\tdistrict: list[0].district,\n\t\t\t\t\t\tdetailAddress: list[0].detailAddress, })\n\t\t\t\t\t} catch (e) {\n\t\t\t\t\t\tconsole.error('自动设置默认地址失败：', e)\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t} catch (e) {\n\t\t\t\tthis.addressList = []\n\t\t\t\tthis.selectedAddress = null\n\t\t\t\tuni.showToast({\n\t\t\t\t\ttitle: '获取地址失败',\n\t\t\t\t\ticon: 'none'\n\t\t\t\t})\n\t\t\t}\n\t\t},\n\t\tgoAddAddress() {\n\t\t\tthis.showAddressPopup = false\n\t\t\tuni.navigateTo({\n\t\t\t\turl: '/pages/address/address'\n\t\t\t})\n\t\t},\n\t\tformatAddress(item) {\n\t\t\treturn [item.province, item.city, item.district, item.detailAddress].filter(Boolean).join('')\n\t\t},\n\t\topenAddressPopup() {\n\t\t\tthis.showAddressPopup = true\n\t\t},\n\t\tasync chooseAddress(item) {\n\t\t\tthis.selectedAddress = item\n\t\t\tthis.showAddressPopup = false\n\n\t\t\tconst token = uni.getStorageSync('Token') || ''\n\t\t\tif (!token) return\n\n\t\t\ttry {\n\t\t\t\tawait api.createRequest({\n\t\t\t\t\turl: '/house/address/update',\n\t\t\t\t\tmethod: 'put',\n\t\t\t\t\ttoken\n\t\t\t\t}, { id: item.id, isDefault: 1, consignee: item.consignee, phone: item.phone, province: '四川省', city: '南充市', district: item.district, detailAddress: item.detailAddress })\n\t\t\t} catch (e) {\n\t\t\t\tconsole.error('设置默认地址失败：', e)\n\t\t\t}\n\t\t},\n\t\topenDateTimePopup() {\n\t\t\tthis.showDateTimePopup = true\n\t\t},\n\t\tonDateChange(e) {\n\t\t\tthis.dateValue = e.detail.value\n\t\t},\n\t\tonTimeChange(e) {\n\t\t\tthis.timeValue = e.detail.value\n\t\t},\n\t\tconfirmDateTime() {\n\t\t\tthis.timeText = `${this.dateValue} ${this.timeValue}`\n\t\t\tthis.showDateTimePopup = false\n\t\t},\n\t\tasync submitReserve() {\n\t\t\tif (!this.selectedAddress || !this.selectedAddress.id) {\n\t\t\t\tuni.showToast({\n\t\t\t\t\ttitle: '请选择服务地址',\n\t\t\t\t\ticon: 'none'\n\t\t\t\t})\n\t\t\t\treturn\n\t\t\t}\n\t\t\tif (!this.timeText) {\n\t\t\t\tuni.showToast({\n\t\t\t\t\ttitle: '请选择预约时间',\n\t\t\t\t\ticon: 'none'\n\t\t\t\t})\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\tif (!this.workerId) {\n\t\t\t\tuni.showToast({\n\t\t\t\t\ttitle: '服务人员信息缺失',\n\t\t\t\t\ticon: 'none'\n\t\t\t\t})\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\tconst token = uni.getStorageSync('Token') || ''\n\t\t\tif (!token) {\n\t\t\t\tuni.navigateTo({\n\t\t\t\t\turl: '/pages/login/index'\n\t\t\t\t})\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\tconst payload = {\n\t\t\t\tworkerId: this.workerId,\n\t\t\t\tcategoryId: this.categoryId,\n\t\t\t\taddressId: 0, //固定写0\n\t\t\t\tstartDate: this.dateValue,\n\t\t\t\tendDate: this.dateValue,\n\t\t\t\tremark: this.remark || ''\n\t\t\t}\n\n\t\t\ttry {\n\t\t\t\t// 第一步：创建订单\n\t\t\t\tconst res = await api.createRequest({\n\t\t\t\t\turl: '/house/order/create',\n\t\t\t\t\tmethod: 'post',\n\t\t\t\t\ttoken\n\t\t\t\t}, payload)\n\n\t\t\t\tconst orderData = res?.data\n\t\t\t\tif (!orderData || !orderData.orderNo) {\n\t\t\t\t\tuni.showToast({\n\t\t\t\t\t\ttitle: res?.msg || '创建订单失败',\n\t\t\t\t\t\ticon: 'none'\n\t\t\t\t\t})\n\t\t\t\t\treturn\n\t\t\t\t}\n\n\t\t\t\t// 第二步：发起支付预下单\n\t\t\t\tuni.showLoading({ title: '支付中...' })\n\t\t\t\tlet prepayRes\n\t\t\t\ttry {\n\t\t\t\t\tprepayRes = await api.createRequest({\n\t\t\t\t\t\turl: `/house/pay/prepay/${orderData.orderNo}`,\n\t\t\t\t\t\tmethod: 'post',\n\t\t\t\t\t\ttoken\n\t\t\t\t\t}, {})\n\t\t\t\t} catch (e) {\n\t\t\t\t\tuni.hideLoading()\n\t\t\t\t\tuni.showToast({ title: '获取支付信息失败', icon: 'none' })\n\t\t\t\t\treturn\n\t\t\t\t}\n\n\t\t\t\tconst payData = prepayRes?.data\n\t\t\t\tif (!payData || !payData.appId) {\n\t\t\t\t\tuni.hideLoading()\n\t\t\t\t\tuni.showToast({\n\t\t\t\t\t\ttitle: prepayRes?.msg || '获取支付信息失败',\n\t\t\t\t\t\ticon: 'none'\n\t\t\t\t\t})\n\t\t\t\t\treturn\n\t\t\t\t}\n\n\t\t\t\t// 第三步：调用微信支付\n\t\t\t\tuni.requestPayment({\n\t\t\t\t\tprovider: 'wxpay',\n\t\t\t\t\ttimeStamp: payData.timeStamp,\n\t\t\t\t\tnonceStr: payData.nonceStr,\n\t\t\t\t\tpackage: payData.packageVal,\n\t\t\t\t\tsignType: payData.signType,\n\t\t\t\t\tpaySign: payData.paySign,\n\t\t\t\t\tsuccess: async () => {\n\t\t\t\t\t\tuni.hideLoading()\n\t\t\t\n\t\t\t\t\t\tuni.showToast({ title: '预约成功', icon: 'success' })\n\t\t\t\t\t\tsetTimeout(() => {\n\t\t\t\t\t\t\tuni.switchTab({ url: '/pages/mine/mine' })\n\t\t\t\t\t\t}, 1200)\n\t\t\t\t\t},\n\t\t\t\t\tfail: (err) => {\n\t\t\t\t\t\tuni.hideLoading()\n\t\t\t\t\t\tconst msg = (err && err.errMsg) || ''\n\t\t\t\t\t\tif (msg.includes('cancel')) {\n\t\t\t\t\t\t\tuni.showToast({ title: '已取消支付', icon: 'none' })\n\t\t\t\t\t\t} else {\n\t\t\t\t\t\t\tuni.showToast({ title: '支付失败，请重试', icon: 'none' })\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\t\t\t\t})\n\t\t\t} catch (e) {\n\t\t\t\tuni.hideLoading()\n\t\t\t\tuni.showToast({\n\t\t\t\t\ttitle: '操作失败，请稍后重试',\n\t\t\t\t\ticon: 'none'\n\t\t\t\t})\n\t\t\t}\n\t\t}\n\t}\n}\n</script>\n\n<style lang=\"scss\" scoped>\n.page {\n\tmin-height: 100vh;\n\tbackground: #f8f9fa;\n\tpadding: 24rpx;\n}\n\n.card {\n\tbackground: #fff;\n\tborder-radius: 20rpx;\n\tpadding: 30rpx 24rpx 40rpx;\n}\n\n.title {\n\tfont-size: 32rpx;\n\tfont-weight: 600;\n\tcolor: #222;\n\tmargin-bottom: 20rpx;\n}\n\n.row {\n\tmargin-bottom: 24rpx;\n}\n\n.label {\n\tdisplay: block;\n\tfont-size: 26rpx;\n\tcolor: #666;\n\tmargin-bottom: 10rpx;\n}\n\n.value {\n\tfont-size: 30rpx;\n\tcolor: #333;\n}\n\n.input {\n\theight: 78rpx;\n\tborder-radius: 12rpx;\n\tbackground: #f4f5f7;\n\tpadding: 0 20rpx;\n\tfont-size: 28rpx;\n}\n\n.picker-input {\n\theight: 78rpx;\n\tborder-radius: 12rpx;\n\tbackground: #f4f5f7;\n\tpadding: 0 20rpx;\n\tdisplay: flex;\n\talign-items: center;\n}\n\n.placeholder-text {\n\tfont-size: 28rpx;\n\tcolor: #999;\n}\n\n.value-text {\n\tfont-size: 28rpx;\n\tcolor: #333;\n}\n\n.submit {\n\tmargin-top: 16rpx;\n\tborder-radius: 40rpx;\n\tbackground: #40ae36;\n\tcolor: #fff;\n\tfont-size: 30rpx;\n}\n\n.remark-input {\n\twidth: 100%;\n\tmin-height: 140rpx;\n\tborder-radius: 12rpx;\n\tbackground: #f4f5f7;\n\tpadding: 18rpx 20rpx;\n\tfont-size: 28rpx;\n\tbox-sizing: border-box;\n}\n\n.datetime-popup {\n\tbackground: #fff;\n\tpadding: 30rpx 24rpx 40rpx;\n}\n\n.popup-title {\n\tfont-size: 32rpx;\n\tfont-weight: 600;\n\tcolor: #222;\n\ttext-align: center;\n\tmargin-bottom: 28rpx;\n}\n\n.popup-row {\n\tdisplay: flex;\n\tjustify-content: space-between;\n\talign-items: center;\n\tmargin-bottom: 20rpx;\n}\n\n.popup-label {\n\tfont-size: 28rpx;\n\tcolor: #666;\n}\n\n.picker-btn {\n\tmin-width: 260rpx;\n\ttext-align: center;\n\tbackground: #f4f5f7;\n\tpadding: 16rpx 20rpx;\n\tborder-radius: 12rpx;\n\tfont-size: 28rpx;\n\tcolor: #333;\n}\n\n.confirm-btn {\n\tmargin-top: 12rpx;\n\tborder-radius: 40rpx;\n\tbackground: #40ae36;\n\tcolor: #fff;\n\tfont-size: 30rpx;\n}\n\n.address-popup {\n\tbackground: #fff;\n\tpadding: 30rpx 24rpx 40rpx;\n}\n\n.address-list {\n\tmax-height: 700rpx;\n\toverflow-y: auto;\n}\n\n.address-item {\n\tdisplay: flex;\n\tjustify-content: space-between;\n\talign-items: center;\n\tpadding: 18rpx 0;\n\tborder-bottom: 1px solid #f1f1f1;\n}\n\n.address-item-main {\n\tflex: 1;\n\tpadding-right: 20rpx;\n}\n\n.address-item-top {\n\tfont-size: 28rpx;\n\tcolor: #333;\n\tmargin-bottom: 8rpx;\n}\n\n.address-name {\n\tmargin-right: 16rpx;\n\tfont-weight: 600;\n}\n\n.address-phone {\n\tcolor: #666;\n\tfont-size: 26rpx;\n}\n\n.address-detail {\n\tfont-size: 24rpx;\n\tcolor: #999;\n}\n\n.address-check {\n\tfont-size: 24rpx;\n\tcolor: #40ae36;\n}\n\n.empty-tip {\n\ttext-align: center;\n\tfont-size: 26rpx;\n\tcolor: #999;\n\tpadding: 30rpx 0;\n\n\t.go-add-btn {\n\t\tmargin-top: 16rpx;\n\t\tborder-radius: 40rpx;\n\t\tbackground: #40ae36;\n\t\tcolor: #fff;\n\t\tfont-size: 28rpx;\n\t}\n}\n\n.add-address-btn {\n\tfont-size: 28rpx;\n\tcolor: #40ae36;\n}\n</style>\n","import mod from \"-!D:\\\\HBuilderX\\\\plugins\\\\uniapp-cli\\\\node_modules\\\\mini-css-extract-plugin\\\\dist\\\\loader.js??ref--8-oneOf-1-0!D:\\\\HBuilderX\\\\plugins\\\\uniapp-cli\\\\node_modules\\\\css-loader\\\\dist\\\\cjs.js??ref--8-oneOf-1-1!D:\\\\HBuilderX\\\\plugins\\\\uniapp-cli\\\\node_modules\\\\@dcloudio\\\\vue-cli-plugin-uni\\\\packages\\\\vue-loader\\\\lib\\\\loaders\\\\stylePostLoader.js!D:\\\\HBuilderX\\\\plugins\\\\uniapp-cli\\\\node_modules\\\\@dcloudio\\\\vue-cli-plugin-uni\\\\packages\\\\webpack-preprocess-loader\\\\index.js??ref--8-oneOf-1-2!D:\\\\HBuilderX\\\\plugins\\\\uniapp-cli\\\\node_modules\\\\postcss-loader\\\\src\\\\index.js??ref--8-oneOf-1-3!D:\\\\HBuilderX\\\\plugins\\\\uniapp-cli\\\\node_modules\\\\@dcloudio\\\\vue-cli-plugin-uni\\\\packages\\\\sass-loader\\\\dist\\\\cjs.js??ref--8-oneOf-1-4!D:\\\\HBuilderX\\\\plugins\\\\uniapp-cli\\\\node_modules\\\\@dcloudio\\\\vue-cli-plugin-uni\\\\packages\\\\webpack-preprocess-loader\\\\index.js??ref--8-oneOf-1-5!D:\\\\HBuilderX\\\\plugins\\\\uniapp-cli\\\\node_modules\\\\@dcloudio\\\\vue-cli-plugin-uni\\\\packages\\\\vue-loader\\\\lib\\\\index.js??vue-l